// FIX: correct path to AI response text
const aiResponse = $input.first().json.output[0].content[0].text;
// Clean up any markdown code fences if present
let cleaned = aiResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
try {
  const parsed = JSON.parse(cleaned);

  // Validate and extract fields
  const title = parsed.pin_title || '';
  const description = parsed.pin_description || '';
  const altText = parsed.alt_text || '';

  // Truncate if over limits (safety net)
  const safePinTitle = title.substring(0, 100);
  const safePinDescription = description.substring(0, 500);
  const safeAltText = altText.substring(0, 500);

  // Pass through original row data + parsed AI content
  const original = $('Get Next Pending Row').first().json;

  return [{
    json: {
      ...original,
      pin_title: safePinTitle,
      pin_description: safePinDescription,
      alt_text: safeAltText
    },
    pairedItem: { item: 0 }
  }];
} catch (e) {
  return [{
    json: {
      pin_title: 'PARSE_ERROR',
      pin_description: 'PARSE_ERROR: ' + e.message,
      alt_text: aiResponse ? aiResponse.substring(0, 200) : 'No AI response received'
    },
    pairedItem: { item: 0 }
  }];
}

