const item = $input.first().json;

// Check if Pinterest returned an error
if (item.code || item.message || !item.id) {
  // Error case
  return [{
    json: {
      status: 'ERROR',
      pin_id: '',
      pinterest_response: JSON.stringify(item).substring(0, 200)
    }
  }];
} else {
  // Success case
  return [{
    json: {
      status: 'PUBLISHED',
      pin_id: item.id || '',
      pinterest_response: JSON.stringify(item).substring(0, 200)
    }
  }];
}

// Get the fragrance name from the queue row - normalize quotes
const fragranceName = $('Get Next Pending Row').first().json.fragrance_name.toLowerCase().replace(/[\u2018\u2019\u2032]/g, "'");

// Get all rows from the Fragrance Database
const dbRows = $('Get Fragrance Database').all();

// Find the best match using short_name
let match = null;
for (const row of dbRows) {
  const shortName = (row.json.short_name || '').toLowerCase().replace(/[\u2018\u2019\u2032]/g, "'");

  const shortNames = shortName.split(',').map(s => s.trim());
  for (const name of shortNames) {
    if (name && fragranceName.includes(name)) {
      match = row.json;
      break;
    }
  }
  if (match) break;
}

// Fallback: try matching words from fragrance_name
if (!match) {
  for (const row of dbRows) {
    const dbName = (row.json.fragrance_name || '').toLowerCase().replace(/[\u2018\u2019\u2032]/g, "'");
    if (fragranceName.split(' ').filter(w => w.length > 3).every(w => dbName.includes(w))) {
      match = row.json;
      break;
    }
  }
}

// Get original row data to pass through
const originalRow = $('Get Next Pending Row').first().json;

// Return matched details WITH original row data combined
if (match) {
  return [{
    json: {
      ...originalRow,
      top_notes: match.top_notes || '',
      middle_notes: match.middle_notes || '',
      base_notes: match.base_notes || '',
      style: match.style || '',
      best_for: match.best_for || '',
      description: (match.description || '').substring(0, 500),
      short_name: match.short_name || '',
      matched: true
    },
    pairedItem: { item: 0 }
  }];
} else {
  return [{
    json: {
      ...originalRow,
      top_notes: '',
      middle_notes: '',
      base_notes: '',
      style: '',
      best_for: '',
      description: '',
      short_name: '',
      matched: false
    },
    pairedItem: { item: 0 }
  }];
}
